import{_ as l,c as a,o as i,R as r}from"./chunks/framework.Dxoqk0BT.js";const b=JSON.parse('{"title":"前端面试官指导手册","description":"","frontmatter":{},"headers":[],"relativePath":"think/6.md","filePath":"think/6.md"}'),e={name:"think/6.md"};function o(d,t,n,s,h,u){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="前端面试官指导手册" tabindex="-1">前端面试官指导手册 <a class="header-anchor" href="#前端面试官指导手册" aria-label="Permalink to &quot;前端面试官指导手册&quot;">​</a></h1><h2 id="一、技术能力评估体系" tabindex="-1">一、技术能力评估体系 <a class="header-anchor" href="#一、技术能力评估体系" aria-label="Permalink to &quot;一、技术能力评估体系&quot;">​</a></h2><table><thead><tr><th>模块</th><th>核心领域</th><th>关键考察点</th></tr></thead><tbody><tr><td><strong>基础核心</strong></td><td>语言规范</td><td>HTML5 语义化、CSS3 (Flexbox/Grid)、JavaScript ES6+、TypeScript</td></tr><tr><td></td><td>浏览器与运行时</td><td>网络基础、网络安全、浏览器原理（渲染、事件循环、Web API、跨域）</td></tr><tr><td><strong>开发框架</strong></td><td>主流框架</td><td>React (Hooks/RSC)、Vue (Composition API)、Next.js/Nuxt、Svelte</td></tr><tr><td><strong>工程化与架构</strong></td><td>开发工具链</td><td>Vite/Webpack/Rollup、pnpm、ESLint/Prettier</td></tr><tr><td></td><td>质量保障</td><td>Jest/Vitest、Playwright、Sentry</td></tr><tr><td></td><td>自动化部署</td><td>CI/CD (GitHub Actions)、Docker、部署策略</td></tr><tr><td></td><td>架构模式</td><td>微前端、Monorepo、低代码引擎、Edge SSR</td></tr><tr><td><strong>全栈技术</strong></td><td>服务端运行时</td><td>Node.js (Express/Koa)、Deno、Bun</td></tr><tr><td></td><td>后端与数据库</td><td>Next.js API、Prisma、Supabase</td></tr><tr><td></td><td>Linux 运维</td><td>systemd、日志分析、性能监控、Nginx、Shell</td></tr><tr><td><strong>跨平台开发</strong></td><td>移动端</td><td>React Native、Flutter、PWA</td></tr><tr><td></td><td>桌面端</td><td>Electron、Tauri</td></tr><tr><td></td><td>小程序</td><td>uniapp、Taro、公众号开发、JSBridge</td></tr><tr><td><strong>前沿与进阶</strong></td><td>可视化与图形</td><td>WebGL、Three.js、WebXR、D3.js</td></tr><tr><td></td><td>性能优化</td><td>Core Web Vitals、代码分割、缓存策略</td></tr><tr><td></td><td>AI &amp; Web3</td><td>Prompt Engineering、TensorFlow.js、Web3.js、智能合约</td></tr></tbody></table><hr><h2 id="二、场景题-软技能评估" tabindex="-1">二、场景题（软技能评估） <a class="header-anchor" href="#二、场景题-软技能评估" aria-label="Permalink to &quot;二、场景题（软技能评估）&quot;">​</a></h2><h3 id="协作能力" tabindex="-1">协作能力 <a class="header-anchor" href="#协作能力" aria-label="Permalink to &quot;协作能力&quot;">​</a></h3><ul><li>前司整个开发协作流程（需求 → 开发 → 测试 → 部署）</li><li>部署方案（CI/CD、发布流程、回滚策略）</li><li>AI 工具使用（Cursor/Copilot/Claude）</li></ul><h3 id="问题解决能力" tabindex="-1">问题解决能力 <a class="header-anchor" href="#问题解决能力" aria-label="Permalink to &quot;问题解决能力&quot;">​</a></h3><ul><li><strong>Debug 思路</strong>：页面白屏/卡顿排查 <ul><li>环境检查、缓存清理、控制台日志</li><li>火焰图分析、二分法定位</li><li>事后复盘、预防机制</li></ul></li></ul><h3 id="抗压能力" tabindex="-1">抗压能力 <a class="header-anchor" href="#抗压能力" aria-label="Permalink to &quot;抗压能力&quot;">​</a></h3><ul><li>前司加班情况</li><li>能否接受偶尔加班到 9 点</li><li>观察情绪基调和态度</li></ul><h3 id="责任心" tabindex="-1">责任心 <a class="header-anchor" href="#责任心" aria-label="Permalink to &quot;责任心&quot;">​</a></h3><ul><li>是否主动处理分外之事（如接手烂摊子项目）</li><li>做事是否闭环（开发 → 测试 → 上线 → 监控）</li><li>失败经历复盘（自我反思能力）</li><li>主动优化意识（如构建速度优化）</li></ul><h3 id="技术深度" tabindex="-1">技术深度 <a class="header-anchor" href="#技术深度" aria-label="Permalink to &quot;技术深度&quot;">​</a></h3><ul><li><strong>印象最深刻的技术方案/项目</strong><ul><li>为什么选择该方案（优势对比）</li><li>为什么不用其他方案（技术选型依据）</li><li>遇到的难点和解决方案</li><li>数据支撑（优化前后对比数据）</li></ul></li></ul><h3 id="学习态度" tabindex="-1">学习态度 <a class="header-anchor" href="#学习态度" aria-label="Permalink to &quot;学习态度&quot;">​</a></h3><ul><li>每份工作的离职原因（深挖动机）</li><li>自我发展规划（3-5 年）</li><li>最近关注的前端新技术</li><li>如何成为合格的前端工程师</li><li>对前端架构的理解</li></ul><h3 id="自我认知" tabindex="-1">自我认知 <a class="header-anchor" href="#自我认知" aria-label="Permalink to &quot;自我认知&quot;">​</a></h3><ul><li>评价自己的优缺点</li><li>观察是否有清晰的自我认知</li></ul><hr><h2 id="三、八股文-核心技术问题" tabindex="-1">三、八股文（核心技术问题） <a class="header-anchor" href="#三、八股文-核心技术问题" aria-label="Permalink to &quot;三、八股文（核心技术问题）&quot;">​</a></h2><h3 id="_1-css-盒模型与性能优化" tabindex="-1">1. CSS 盒模型与性能优化 <a class="header-anchor" href="#_1-css-盒模型与性能优化" aria-label="Permalink to &quot;1. CSS 盒模型与性能优化&quot;">​</a></h3><ul><li>CSS 盒模型（标准盒/IE 盒）</li><li>BFC（块级格式化上下文）及应用场景</li><li>避免重排和重绘的方法</li><li>哪些操作会引起强制布局</li></ul><h3 id="_2-javascript-事件循环" tabindex="-1">2. JavaScript 事件循环 <a class="header-anchor" href="#_2-javascript-事件循环" aria-label="Permalink to &quot;2. JavaScript 事件循环&quot;">​</a></h3><ul><li>调用栈、任务队列的工作机制</li><li>微任务与宏任务的区别</li><li>为什么要区分宏任务和微任务</li><li>常见的微任务和宏任务类型</li></ul><h3 id="_3-vue-响应式原理" tabindex="-1">3. Vue 响应式原理 <a class="header-anchor" href="#_3-vue-响应式原理" aria-label="Permalink to &quot;3. Vue 响应式原理&quot;">​</a></h3><ul><li>Vue2：Object.defineProperty（优缺点）</li><li>Vue3：Proxy（优缺点）</li><li>两者对比及性能差异</li></ul><h3 id="_4-浏览器渲染流程" tabindex="-1">4. 浏览器渲染流程 <a class="header-anchor" href="#_4-浏览器渲染流程" aria-label="Permalink to &quot;4. 浏览器渲染流程&quot;">​</a></h3><ul><li>从输入 URL 到页面显示的完整过程</li><li>DNS 解析、TCP 连接、HTTP 请求</li><li>浏览器解析、渲染树构建、绘制</li></ul><h3 id="_5-webpack-构建流程" tabindex="-1">5. Webpack 构建流程 <a class="header-anchor" href="#_5-webpack-构建流程" aria-label="Permalink to &quot;5. Webpack 构建流程&quot;">​</a></h3><ul><li>初始化、编译、输出三个阶段</li><li>Loader 和 Plugin 的作用</li><li>常见优化手段</li></ul><h3 id="_6-前端性能优化体系" tabindex="-1">6. 前端性能优化体系 <a class="header-anchor" href="#_6-前端性能优化体系" aria-label="Permalink to &quot;6. 前端性能优化体系&quot;">​</a></h3><ul><li><strong>资源优化</strong>：压缩、合并、Tree Shaking</li><li><strong>网络优化</strong>：HTTP/2、CDN、预加载</li><li><strong>加载优化</strong>：懒加载、代码分割、骨架屏</li><li><strong>运行优化</strong>：防抖节流、虚拟列表、Web Worker</li><li><strong>缓存优化</strong>：强缓存、协商缓存、LocalStorage</li><li><strong>接口优化</strong>：并发控制、请求合并、接口缓存</li><li><strong>性能监控</strong>：Lighthouse、性能 API、埋点上报</li></ul><h3 id="_7-浏览器兼容性保障" tabindex="-1">7. 浏览器兼容性保障 <a class="header-anchor" href="#_7-浏览器兼容性保障" aria-label="Permalink to &quot;7. 浏览器兼容性保障&quot;">​</a></h3><ul><li>Polyfill 方案（core-js、@babel/preset-env）</li><li>Browserslist 配置</li><li>CSS 前缀自动化（Autoprefixer）</li><li>兼容性测试流程</li></ul><hr><h2 id="四、面试评分维度" tabindex="-1">四、面试评分维度 <a class="header-anchor" href="#四、面试评分维度" aria-label="Permalink to &quot;四、面试评分维度&quot;">​</a></h2><ul><li><strong>技术深度</strong>（30%）：核心技术理解深度、源码阅读能力</li><li><strong>技术广度</strong>（20%）：技术栈覆盖面、新技术学习</li><li><strong>工程能力</strong>（20%）：工程化实践、代码规范、架构设计</li><li><strong>问题解决</strong>（15%）：Debug 能力、技术选型、方案设计</li><li><strong>软技能</strong>（15%）：沟通协作、责任心、抗压能力</li></ul><hr><h2 id="五、面试技巧" tabindex="-1">五、面试技巧 <a class="header-anchor" href="#五、面试技巧" aria-label="Permalink to &quot;五、面试技巧&quot;">​</a></h2><ol><li><strong>循序渐进</strong>：由浅入深，从基础到进阶</li><li><strong>追问细节</strong>：不满足于表面回答，深挖实现原理</li><li><strong>场景结合</strong>：结合实际项目场景提问</li><li><strong>观察态度</strong>：注意候选人的情绪、思考方式</li><li><strong>给予机会</strong>：遇到不会的问题，可以引导或换个角度</li></ol>',41)])])}const g=l(e,[["render",o]]);export{b as __pageData,g as default};
